1	interface QuoteStep {
2	  op: "quote";
3	  items: { type: string }[];
4	}
5	
6	interface Scenario {
7	  customer: { yearsWithMHPCO: number };
8	  steps: QuoteStep[];
9	}
10	
11	const BASE_PREMIUM: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	};
18	
19	const FIRST_INSURANCE_RATE = 0.1;
20	const PROCESSING_FEE = 5;
21	
22	const quotePremium = (step: QuoteStep): number => {
23	  const policyBase = step.items.reduce(
24	    (sum, item) => sum + BASE_PREMIUM[item.type],
25	    0,
26	  );
27	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
28	  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
29	};
30	
31	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
32	  return {
33	    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
34	  };
35	};
